-- ── appril_capabilities: base de conocimiento de lo que hace Appril ──────────
-- Fuente de verdad ÚNICA de las funcionalidades del producto, editable al
-- instante (UPDATE/INSERT o vía MCP), sin redeploy. La consumen los agentes por
-- la función appril_capabilities_search (busca por dolor/tema, no vuelca todo).
-- Se aplica idéntica en los DOS proyectos Supabase (producto y CRM).

create table if not exists public.appril_capabilities (
  id          bigint generated always as identity primary key,
  orden       integer not null default 0,
  grupo       text not null,
  que_hace    text not null,
  explicacion text not null,
  publico     text not null default 'ambos' check (publico in ('paciente','profesional','ambos')),
  keywords    text not null default '',
  activa      boolean not null default true,
  updated_at  timestamptz not null default now()
);

-- Búsqueda: tsvector en español, que_hace y keywords pesan más que la explicación.
alter table public.appril_capabilities
  add column if not exists busqueda tsvector
  generated always as (
    setweight(to_tsvector('spanish', coalesce(que_hace,'')), 'A') ||
    setweight(to_tsvector('spanish', coalesce(keywords,'')), 'A') ||
    setweight(to_tsvector('spanish', coalesce(explicacion,'')), 'B')
  ) stored;
create index if not exists idx_appril_capabilities_busqueda on public.appril_capabilities using gin (busqueda);

alter table public.appril_capabilities enable row level security;
drop policy if exists appril_capabilities_read on public.appril_capabilities;
create policy appril_capabilities_read on public.appril_capabilities for select to authenticated, anon using (activa);

-- Seed (idempotente: vacía y recarga, para que re-aplicar refleje el Excel actual).
truncate public.appril_capabilities restart identity;

-- Búsqueda por dolor/tema para los agentes. Devuelve las N más relevantes.
-- Si la query no matchea nada por full-text, cae a ILIKE sobre keywords+que_hace.
create or replace function public.appril_capabilities_search(
  p_query text, p_limit integer default 4, p_publico text default null
) returns table (grupo text, que_hace text, explicacion text, publico text)
language sql stable security definer set search_path = public as $$
  with q as (select nullif(replace(plainto_tsquery('spanish', coalesce(p_query,''))::text, '&', '|'), '')::tsquery as tsq)
  select c.grupo, c.que_hace, c.explicacion, c.publico
  from appril_capabilities c, q
  where c.activa
    and (p_publico is null or c.publico = p_publico or c.publico = 'ambos')
    and (
      (q.tsq is not null and c.busqueda @@ q.tsq)
      or c.que_hace ilike '%'||p_query||'%'
      or c.keywords ilike '%'||p_query||'%'
    )
  order by ts_rank(c.busqueda, q.tsq) desc nulls last, c.orden
  limit greatest(1, least(p_limit, 10));
$$;

-- Catálogo completo agrupado (para el espejo en appril-growth y para "qué hace Appril" completo).
create or replace function public.appril_capabilities_all()
returns table (grupo text, que_hace text, explicacion text, publico text)
language sql stable security definer set search_path = public as $$
  select grupo, que_hace, explicacion, publico
  from appril_capabilities where activa order by orden;
$$;

revoke all on function public.appril_capabilities_search(text,integer,text) from public;
revoke all on function public.appril_capabilities_all() from public;
grant execute on function public.appril_capabilities_search(text,integer,text) to anon, authenticated, service_role;
grant execute on function public.appril_capabilities_all() to anon, authenticated, service_role;
